    const int64_t N = x.size(0);
    const int64_t Cin = x.size(1);
    const int64_t H = x.size(2);
    const int64_t W = x.size(3);
    const int64_t Cout = weight.size(0);
    const int64_t Kh = weight.size(2);
    const int64_t Kw = weight.size(3);
    TORCH_CHECK(Cin == weight.size(1), \"Cin mismatch\");
    TORCH_CHECK(H >= Kh && W >= Kw, \"Invalid spatial size for valid conv\");
    auto out_sizes = at::IntArrayRef({N, Cout, H - Kh + 1, W - Kw + 1});
    at::Tensor y = at::empty(out_sizes, x.options());

    EXEC_NPU_CMD(aclnnConvStandard2dSquareInputSquareKernelCustom, x, weight, y);
